/**
 * starfield.js — Interactive Star Viewer
 *
 * Real-time night sky from Los Angeles (34.05°N, 118.24°W).
 * Camera-frame projection in horizontal space — flat horizon at all azimuths.
 *
 * Features: star colors (B-V), twinkle, type-aware DSOs, coordinate grids,
 * magnitude-based zoom detail, live LA clock.
 *
 * Data: data/stars.json (generated by scripts/process_stars.py)
 */

import { fovToScale }      from './sky/projection.js';
import { julianDate, lst, hzToEq } from './sky/time.js';
import { planetPositions }  from './sky/planets.js';

// --- Observer (Los Angeles) ---

const LAT_LA  =  34.0522;
const LON_LA  = -118.2437;
const SIN_LAT = Math.sin(LAT_LA * Math.PI / 180);
const COS_LAT = Math.cos(LAT_LA * Math.PI / 180);

// --- Constants ---

const D2R = Math.PI / 180;
const R2D = 180 / Math.PI;

const MAG_BRIGHT = -1.5;
const MAG_DIM    =  6.5;
const R_MAX      =  4.0;
const R_MIN      =  0.5;
const A_MAX      =  1.0;
const A_MIN      =  0.15;

const FOV_DEFAULT  =  90;
const FOV_MIN      =  15;
const FOV_MAX      = 150;
const ALT_MIN      = -85;
const ALT_MAX      =  85;

const LABEL_FADE_DEG    =  6;
const BELOW_HORIZON_DIM = 0.35;
const MAG_FADE_BAND     = 0.5;   // magnitude band for smooth star fade
const OBLIQUITY         = 23.43928; // ecliptic obliquity (degrees, J2000)

const CARDINALS = [
  { az:   0, label: 'N' },
  { az:  90, label: 'E' },
  { az: 180, label: 'S' },
  { az: 270, label: 'W' },
];

// --- Accessibility ---

const reducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

// --- B-V Color Index → RGB Lookup Table ---

const COLOR_LUT = buildColorLUT();

function buildColorLUT() {
  // Anchor points: B-V → [R, G, B]
  const anchors = [
    [-0.33, 155, 176, 255],
    [-0.17, 170, 191, 255],
    [ 0.00, 192, 209, 255],
    [ 0.15, 212, 225, 255],
    [ 0.30, 237, 238, 255],
    [ 0.45, 255, 251, 245],
    [ 0.60, 255, 244, 232],
    [ 0.80, 255, 227, 196],
    [ 1.00, 255, 210, 161],
    [ 1.40, 255, 187, 123],
    [ 2.00, 255, 160, 100],
  ];
  const lut = new Array(256);
  for (let i = 0; i < 256; i++) {
    const bv = (i / 255) * 2.4 - 0.4; // map [0..255] → [-0.4..2.0]
    // Find surrounding anchors
    let lo = 0, hi = anchors.length - 1;
    for (let j = 0; j < anchors.length - 1; j++) {
      if (bv >= anchors[j][0] && bv <= anchors[j + 1][0]) { lo = j; hi = j + 1; break; }
    }
    if (bv <= anchors[0][0]) { lo = 0; hi = 0; }
    if (bv >= anchors[anchors.length - 1][0]) { lo = anchors.length - 1; hi = lo; }
    const t = lo === hi ? 0 : (bv - anchors[lo][0]) / (anchors[hi][0] - anchors[lo][0]);
    const r = Math.round(anchors[lo][1] + (anchors[hi][1] - anchors[lo][1]) * t);
    const g = Math.round(anchors[lo][2] + (anchors[hi][2] - anchors[lo][2]) * t);
    const b = Math.round(anchors[lo][3] + (anchors[hi][3] - anchors[lo][3]) * t);
    lut[i] = `${r},${g},${b}`;
  }
  return lut;
}

function bvToColor(ci) {
  if (ci == null) return '220,220,255'; // default warm white
  const idx = Math.max(0, Math.min(255, Math.round((ci + 0.4) / 2.4 * 255)));
  return COLOR_LUT[idx];
}

// --- DOM ---

const canvas   = document.getElementById('sky-canvas');
const ctx      = canvas.getContext('2d');
const infoEl   = document.getElementById('info');
const coordsEl = document.getElementById('cursor-coords');
const clockTimeEl = document.getElementById('clock-time');
const clockDateEl = document.getElementById('clock-date');

// --- State ---

let data = null;

const view = { az: 180.0, alt: 45.0, fov: FOV_DEFAULT };
const drag = { active: false, prevX: 0, prevY: 0 };
const overlays = { altAzGrid: false, eqGrid: false, ecliptic: false };

let cursorPx = -1;
let cursorPy = -1;
let W = 0, H = 0, cx = 0, cy = 0;

// --- Canvas sizing ---

function resize() {
  const dpr = window.devicePixelRatio || 1;
  W = window.innerWidth;
  H = window.innerHeight;
  canvas.width  = Math.round(W * dpr);
  canvas.height = Math.round(H * dpr);
  canvas.style.width  = W + 'px';
  canvas.style.height = H + 'px';
  ctx.scale(dpr, dpr);
  cx = W / 2;
  cy = H / 2;
}

// --- Visual mapping ---

function magToRadius(mag) {
  const t = Math.min(1, Math.max(0, (mag - MAG_BRIGHT) / (MAG_DIM - MAG_BRIGHT)));
  return R_MAX + (R_MIN - R_MAX) * t;
}

function magToAlpha(mag) {
  const t = Math.min(1, Math.max(0, (mag - MAG_BRIGHT) / (MAG_DIM - MAG_BRIGHT)));
  return A_MAX + (A_MIN - A_MAX) * t;
}

function edgeFade(cosAngle) {
  const theta   = Math.acos(Math.max(-1, Math.min(1, cosAngle))) * R2D;
  const halfFov = view.fov / 2;
  if (theta >= halfFov) return 0;
  if (theta <= halfFov - LABEL_FADE_DEG) return 1;
  return (halfFov - theta) / LABEL_FADE_DEG;
}

/** FOV → magnitude limit for zoom detail. */
function fovMagLimit(fovDeg) {
  const m = fovDeg >= 90
    ? 6.5 + (fovDeg - 90) * (-2.0 / 60)
    : 6.5 + (fovDeg - 90) * (0.5 / 75);
  return Math.max(1.0, m);
}

// ============================================================
// Camera-frame projection (horizontal space)
// ============================================================

function buildViewFrame(altDeg, azDeg, lstDeg) {
  const altR = altDeg * D2R, azR = azDeg * D2R;
  const sinAz = Math.sin(azR), cosAz = Math.cos(azR);
  const sinAlt = Math.sin(altR), cosAlt = Math.cos(altR);
  return {
    rX: cosAz, rY: -sinAz,
    uX: -sinAz * sinAlt, uY: -cosAz * sinAlt, uZ: cosAlt,
    fX: sinAz * cosAlt, fY: cosAz * cosAlt, fZ: sinAlt,
    lstDeg,
  };
}

function projectStar(ra, dec, vf) {
  const H = (vf.lstDeg - ra * 15) * D2R;
  const decR = dec * D2R;
  const sd = Math.sin(decR), cd = Math.cos(decR);
  const ch = Math.cos(H), sh = Math.sin(H);
  const xHz = -cd * sh;
  const yHz = COS_LAT * sd - SIN_LAT * cd * ch;
  const zHz = SIN_LAT * sd + COS_LAT * cd * ch;
  const camX = xHz * vf.rX + yHz * vf.rY;
  const camY = xHz * vf.uX + yHz * vf.uY + zHz * vf.uZ;
  const cosA = xHz * vf.fX + yHz * vf.fY + zHz * vf.fZ;
  const D = 1 + cosA;
  if (D < 0.001) return null;
  return { x: camX / D, y: camY / D, cosAngle: cosA, belowHorizon: zHz < 0 };
}

function projectHzPoint(alt, az, vf) {
  const altR = alt * D2R, azR = az * D2R;
  const xHz = Math.cos(altR) * Math.sin(azR);
  const yHz = Math.cos(altR) * Math.cos(azR);
  const zHz = Math.sin(altR);
  const camX = xHz * vf.rX + yHz * vf.rY;
  const camY = xHz * vf.uX + yHz * vf.uY + zHz * vf.uZ;
  const cosA = xHz * vf.fX + yHz * vf.fY + zHz * vf.fZ;
  const D = 1 + cosA;
  if (D < 0.001) return null;
  return { x: camX / D, y: camY / D, cosAngle: cosA };
}

function screenToRaDec(px, py, scale, vf) {
  const x = (px - cx) / scale, y = (cy - py) / scale;
  const rho = Math.sqrt(x * x + y * y);
  if (rho < 1e-10) return hzToEq(view.alt, view.az, vf.lstDeg, LAT_LA);
  const c = 2 * Math.atan(rho);
  const cosC = Math.cos(c), sinC = Math.sin(c);
  const camX = x * sinC / rho, camY = y * sinC / rho, camZ = cosC;
  const xHz = camX * vf.rX + camY * vf.uX + camZ * vf.fX;
  const yHz = camX * vf.rY + camY * vf.uY + camZ * vf.fY;
  const zHz = camY * vf.uZ + camZ * vf.fZ;
  const alt = Math.asin(Math.max(-1, Math.min(1, zHz))) * R2D;
  const az = ((Math.atan2(xHz, yHz) * R2D) + 360) % 360;
  return hzToEq(alt, az, vf.lstDeg, LAT_LA);
}

// ============================================================
// Render layers
// ============================================================

function renderStars(scale, vf) {
  const cullCos = Math.cos((view.fov / 2 + 10) * D2R);
  const magLimit = fovMagLimit(view.fov);
  const t = performance.now() * 0.001;

  for (let i = 0; i < data.stars.length; i++) {
    const s = data.stars[i];
    const ra = s[0], dec = s[1], mag = s[2], ci = s[3];
    if (mag > magLimit) break; // sorted by magnitude — rest are dimmer

    const p = projectStar(ra, dec, vf);
    if (!p || p.cosAngle < cullCos) continue;

    const px = cx + p.x * scale;
    const py = cy - p.y * scale;
    const r = magToRadius(mag);
    let a = magToAlpha(mag) * (p.belowHorizon ? BELOW_HORIZON_DIM : 1.0);

    // Magnitude fade band
    if (mag > magLimit - MAG_FADE_BAND) {
      a *= (magLimit - mag) / MAG_FADE_BAND;
    }

    // Twinkle for bright stars
    if (mag < 4.0 && !p.belowHorizon && !reducedMotion) {
      const phase = ((i * 2654435761) >>> 0) & 0xFFFF;
      a *= 0.85 + 0.15 * (
        0.6 * Math.sin(t * 3.7 + phase * 0.001) +
        0.4 * Math.sin(t * 7.1 + phase * 0.0017)
      );
    }

    const rgb = bvToColor(ci);

    ctx.beginPath();
    ctx.arc(px, py, r, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(${rgb},${a.toFixed(3)})`;
    ctx.fill();

    // Glow for bright stars
    if (mag < 2.0 && !p.belowHorizon) {
      const glowR = r * 5;
      const grad = ctx.createRadialGradient(px, py, r * 0.5, px, py, glowR);
      grad.addColorStop(0, `rgba(${rgb},${(a * 0.35).toFixed(3)})`);
      grad.addColorStop(1, `rgba(${rgb},0)`);
      ctx.beginPath();
      ctx.arc(px, py, glowR, 0, Math.PI * 2);
      ctx.fillStyle = grad;
      ctx.fill();
    }
  }
}

function renderConstellationLines(scale, vf) {
  const cullCos = Math.cos((view.fov / 2 + 30) * D2R);
  ctx.strokeStyle = 'rgba(255,255,255,0.22)';
  ctx.lineWidth = 0.8;

  for (const c of data.constellations) {
    for (const seg of c.resolvedLines) {
      const p1 = projectStar(seg[0], seg[1], vf);
      const p2 = projectStar(seg[2], seg[3], vf);
      if (!p1 || !p2) continue;
      if (p1.cosAngle < cullCos && p2.cosAngle < cullCos) continue;
      ctx.beginPath();
      ctx.moveTo(cx + p1.x * scale, cy - p1.y * scale);
      ctx.lineTo(cx + p2.x * scale, cy - p2.y * scale);
      ctx.stroke();
    }
  }
}

function renderDSOs(scale, vf) {
  const cullCos = Math.cos((view.fov / 2 + 5) * D2R);

  for (let di = 0; di < data.dsos.length; di++) {
    const d = data.dsos[di];
    const p = projectStar(d.ra, d.dec, vf);
    if (!p || p.cosAngle < cullCos) continue;

    const px = cx + p.x * scale;
    const py = cy - p.y * scale;
    const screenR = Math.max(6, d.size * D2R * scale);
    const b = d.brightness;

    if (d.type === 'nebula') {
      // Reddish-pink diffuse glow
      ctx.fillStyle = `rgba(255,180,200,${(b * 0.25).toFixed(3)})`;
      ctx.beginPath();
      ctx.arc(px, py, screenR * 0.4, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = `rgba(200,150,180,${(b * 0.10).toFixed(3)})`;
      ctx.beginPath();
      ctx.arc(px, py, screenR, 0, Math.PI * 2);
      ctx.fill();
    } else if (d.type === 'galaxy') {
      // Warm ellipse
      const angle = (di * 137.508) * D2R; // deterministic rotation
      ctx.save();
      ctx.translate(px, py);
      ctx.rotate(angle);
      ctx.fillStyle = `rgba(255,240,200,${(b * 0.20).toFixed(3)})`;
      ctx.beginPath();
      ctx.ellipse(0, 0, screenR * 0.6, screenR * 0.25, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = `rgba(255,230,180,${(b * 0.08).toFixed(3)})`;
      ctx.beginPath();
      ctx.ellipse(0, 0, screenR, screenR * 0.45, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
    } else if (d.type === 'open_cluster') {
      // Scattered dots
      ctx.fillStyle = `rgba(200,220,255,${(b * 0.35).toFixed(3)})`;
      for (let j = 0; j < 7; j++) {
        const a2 = (j * 137.508 + di * 50) * D2R;
        const r2 = screenR * 0.4 * (0.3 + (j % 3) * 0.35);
        ctx.beginPath();
        ctx.arc(px + Math.cos(a2) * r2, py + Math.sin(a2) * r2, 1.5, 0, Math.PI * 2);
        ctx.fill();
      }
    } else if (d.type === 'globular_cluster') {
      // Concentrated center glow
      ctx.fillStyle = `rgba(255,240,210,${(b * 0.35).toFixed(3)})`;
      ctx.beginPath();
      ctx.arc(px, py, screenR * 0.25, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = `rgba(255,230,200,${(b * 0.12).toFixed(3)})`;
      ctx.beginPath();
      ctx.arc(px, py, screenR * 0.6, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = `rgba(240,220,190,${(b * 0.05).toFixed(3)})`;
      ctx.beginPath();
      ctx.arc(px, py, screenR, 0, Math.PI * 2);
      ctx.fill();
    }
  }
}

// --- Milky Way ---

let milkyWayPoints = null;

function buildMilkyWayPoints(waypoints) {
  // Remove duplicate closing point if first == last (avoids doubled seam segment)
  const wp = (waypoints[0].ra === waypoints[waypoints.length - 1].ra &&
              waypoints[0].dec === waypoints[waypoints.length - 1].dec)
    ? waypoints.slice(0, -1) : waypoints;
  const pts = [];
  const n = wp.length;
  const STEPS = 8;
  for (let i = 0; i < n; i++) {
    const a = wp[(i - 1 + n) % n];
    const b = wp[i];
    const c = wp[(i + 1) % n];
    const d = wp[(i + 2) % n];
    for (let s = 0; s < STEPS; s++) {
      const t = s / STEPS;
      const t2 = t * t, t3 = t2 * t;
      const ra  = 0.5 * ((2*b.ra) + (-a.ra+c.ra)*t + (2*a.ra-5*b.ra+4*c.ra-d.ra)*t2 + (-a.ra+3*b.ra-3*c.ra+d.ra)*t3);
      const dec = 0.5 * ((2*b.dec) + (-a.dec+c.dec)*t + (2*a.dec-5*b.dec+4*c.dec-d.dec)*t2 + (-a.dec+3*b.dec-3*c.dec+d.dec)*t3);
      const w = b.width + (c.width - b.width) * t;
      // Deterministic hash for offset points (avoids Math.random — stable across reloads)
      const seed = ((i * 8 + s) * 2654435761) >>> 0;
      const rA = ((seed & 0xFFFF) / 0xFFFF - 0.5);
      const rD = (((seed >>> 16) & 0xFFFF) / 0xFFFF - 0.5);
      pts.push({ ra, dec, width: w * 0.5 });
      pts.push({ ra: ra + rA * w * 0.02, dec: dec + rD * w * 0.3, width: w * 0.3 });
    }
  }
  return pts;
}

function renderMilkyWay(scale, vf) {
  if (!milkyWayPoints) return;
  ctx.fillStyle = 'rgba(180,180,210,0.008)';
  for (const pt of milkyWayPoints) {
    const p = projectStar(pt.ra, pt.dec, vf);
    if (!p) continue;
    if (p.cosAngle < Math.cos((view.fov / 2 + pt.width) * D2R)) continue;
    const px = cx + p.x * scale, py = cy - p.y * scale;
    ctx.beginPath();
    ctx.arc(px, py, pt.width * D2R * scale, 0, Math.PI * 2);
    ctx.fill();
  }
}

// --- Grid overlays ---

/** Draw a projected grid line using a callback (avoids per-frame array allocations). */
function drawGridLine(count, getPoint, scale) {
  let penDown = false;
  for (let i = 0; i < count; i++) {
    const p = getPoint(i);
    if (!p || p.cosAngle < 0.01) { penDown = false; continue; }
    const px = cx + p.x * scale, py = cy - p.y * scale;
    if (!penDown) { ctx.moveTo(px, py); penDown = true; }
    else ctx.lineTo(px, py);
  }
}

function renderAltAzGrid(scale, vf) {
  ctx.strokeStyle = 'rgba(100,150,200,0.25)';
  ctx.lineWidth = 0.5;

  for (let alt = -80; alt <= 80; alt += 10) {
    if (alt === 0) continue;
    ctx.beginPath();
    drawGridLine(181, i => projectHzPoint(alt, i * 2, vf), scale);
    ctx.stroke();
  }

  for (let az = 0; az < 360; az += 15) {
    ctx.beginPath();
    drawGridLine(91, i => projectHzPoint(-90 + i * 2, az, vf), scale);
    ctx.stroke();
  }
}

function renderEqGrid(scale, vf) {
  for (let dec = -80; dec <= 80; dec += 10) {
    ctx.strokeStyle = dec === 0 ? 'rgba(100,200,150,0.5)' : 'rgba(100,200,150,0.25)';
    ctx.lineWidth = dec === 0 ? 1.0 : 0.5;
    ctx.beginPath();
    drawGridLine(181, i => projectStar(i * 24 / 180, dec, vf), scale);
    ctx.stroke();
  }

  ctx.strokeStyle = 'rgba(100,200,150,0.25)';
  ctx.lineWidth = 0.5;
  for (let raH = 0; raH < 24; raH++) {
    ctx.beginPath();
    drawGridLine(91, i => projectStar(raH, -90 + i * 2, vf), scale);
    ctx.stroke();
  }
}

function renderEcliptic(scale, vf) {
  const oblR = OBLIQUITY * D2R;
  ctx.strokeStyle = 'rgba(200,200,100,0.35)';
  ctx.lineWidth = 1.0;
  ctx.setLineDash([6, 4]);
  ctx.beginPath();
  drawGridLine(361, i => {
    const lamR = i * D2R;
    const raRad = Math.atan2(Math.sin(lamR) * Math.cos(oblR), Math.cos(lamR));
    const decRad = Math.asin(Math.sin(lamR) * Math.sin(oblR));
    return projectStar(((raRad * R2D + 360) % 360) / 15, decRad * R2D, vf);
  }, scale);
  ctx.stroke();
  ctx.setLineDash([]);
}

// --- Horizon, Cardinals ---

function renderHorizon(scale, vf) {
  ctx.beginPath();
  let penDown = false;
  for (let i = 0; i <= 360; i++) {
    const p = projectHzPoint(0, i % 360, vf);
    if (!p || p.cosAngle < 0.01) { penDown = false; continue; }
    const px = cx + p.x * scale, py = cy - p.y * scale;
    if (!penDown) { ctx.moveTo(px, py); penDown = true; }
    else ctx.lineTo(px, py);
  }
  ctx.strokeStyle = 'rgba(255,255,255,0.55)';
  ctx.lineWidth = 1.5;
  ctx.stroke();
}

function renderPlanets(scale, vf, jd) {
  const cullCos = Math.cos((view.fov / 2 + 5) * D2R);
  const planets = planetPositions(jd);

  for (const planet of planets) {
    const p = projectStar(planet.ra, planet.dec, vf);
    if (!p || p.cosAngle < cullCos) continue;
    const alpha = edgeFade(p.cosAngle);
    if (alpha <= 0) continue;

    const a = alpha * (p.belowHorizon ? BELOW_HORIZON_DIM : 1.0);
    const px = cx + p.x * scale, py = cy - p.y * scale;
    const r = planet.screenR;

    const grad = ctx.createRadialGradient(px, py, 0, px, py, r * 2.5);
    grad.addColorStop(0, `rgba(255,165,0,${(a * 0.9).toFixed(3)})`);
    grad.addColorStop(0.5, `rgba(255,140,0,${(a * 0.4).toFixed(3)})`);
    grad.addColorStop(1, 'rgba(255,120,0,0)');
    ctx.beginPath();
    ctx.arc(px, py, r * 2.5, 0, Math.PI * 2);
    ctx.fillStyle = grad;
    ctx.fill();

    ctx.beginPath();
    ctx.arc(px, py, r, 0, Math.PI * 2);
    ctx.fillStyle = `rgba(255,180,60,${a.toFixed(3)})`;
    ctx.fill();

    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    ctx.font = '11px sans-serif';
    ctx.fillStyle = `rgba(255,200,100,${(a * 0.85).toFixed(3)})`;
    ctx.fillText(planet.name, px, py + r + 4);
  }
}

function renderCardinals(scale, vf) {
  ctx.font = 'bold 13px monospace';
  ctx.textAlign = 'center';
  ctx.textBaseline = 'bottom';

  for (const { az, label } of CARDINALS) {
    const p = projectHzPoint(0, az, vf);
    if (!p || p.cosAngle < 0.01) continue;
    const alpha = edgeFade(p.cosAngle);
    if (alpha <= 0) continue;
    const px = cx + p.x * scale, py = cy - p.y * scale;

    ctx.strokeStyle = `rgba(255,255,255,${(0.75 * alpha).toFixed(3)})`;
    ctx.lineWidth = 1.5;
    ctx.beginPath();
    ctx.moveTo(px, py - 7);
    ctx.lineTo(px, py + 7);
    ctx.stroke();

    ctx.fillStyle = `rgba(255,255,255,${(0.9 * alpha).toFixed(3)})`;
    ctx.fillText(label, px, py - 10);
  }
}

function renderLabels(scale, vf) {
  ctx.textAlign = 'center';
  ctx.textBaseline = 'bottom';
  ctx.font = '13px sans-serif';

  for (const c of data.constellations) {
    const p = projectStar(c.label_ra, c.label_dec, vf);
    if (!p) continue;
    const alpha = edgeFade(p.cosAngle);
    if (alpha <= 0) continue;
    const px = cx + p.x * scale, py = cy - p.y * scale;
    ctx.fillStyle = `rgba(255,255,255,${(0.45 * alpha).toFixed(3)})`;
    ctx.fillText(c.name, px, py - 10);
  }

  ctx.textBaseline = 'top';
  ctx.font = '11px sans-serif';
  for (const d of data.dsos) {
    const p = projectStar(d.ra, d.dec, vf);
    if (!p) continue;
    const alpha = edgeFade(p.cosAngle);
    if (alpha <= 0) continue;
    const px = cx + p.x * scale, py = cy - p.y * scale;
    ctx.fillStyle = `rgba(180,180,255,${(0.40 * alpha).toFixed(3)})`;
    ctx.fillText(d.name, px, py + 10);
  }
}

// --- Clock ---

const clockFmt = new Intl.DateTimeFormat('en-US', {
  timeZone: 'America/Los_Angeles',
  hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false,
});
const dateFmt = new Intl.DateTimeFormat('en-US', {
  timeZone: 'America/Los_Angeles',
  year: 'numeric', month: 'short', day: '2-digit', weekday: 'short',
});

let _lastClockSec = -1;
function updateClock() {
  if (!clockTimeEl) return;
  const now = new Date();
  const s = now.getSeconds();
  if (s === _lastClockSec) return;
  _lastClockSec = s;
  clockTimeEl.textContent = clockFmt.format(now);
  clockDateEl.textContent = dateFmt.format(now);
}

// --- Info panel ---

function updateInfo(scale, vf) {
  const lstH = Math.floor(vf.lstDeg / 15);
  const lstM = Math.floor((vf.lstDeg / 15 - lstH) * 60);
  const magLimit = fovMagLimit(view.fov);

  infoEl.innerHTML =
    `<b>Star Viewer — Los Angeles</b><br>` +
    `Stars: ${data.meta.star_count} | Mag limit: ${magLimit.toFixed(1)}<br>` +
    `LST: ${lstH}h${String(lstM).padStart(2,'0')}m &nbsp; Az ${view.az.toFixed(1)}° Alt ${view.alt.toFixed(1)}°<br>` +
    `FOV: ${view.fov.toFixed(1)}° &nbsp; [G] grid [Q] eq [E] ecliptic`;

  if (cursorPx >= 0) {
    const coords = screenToRaDec(cursorPx, cursorPy, scale, vf);
    const ch = Math.floor(coords.ra);
    const cm = Math.floor((coords.ra - ch) * 60);
    coordsEl.textContent =
      `RA ${ch}h${String(cm).padStart(2,'0')}m  Dec ${coords.dec > 0 ? '+' : ''}${coords.dec.toFixed(1)}°`;
  }
}

// --- Drag ---

function applyDragRotation(alt, az, dx, dy, degPerPx) {
  const cosAlt = Math.cos(alt * D2R);
  let newAz = ((az - dx * degPerPx / Math.max(cosAlt, 0.15)) % 360 + 360) % 360;
  let newAlt = alt + dy * degPerPx;
  newAlt = Math.max(ALT_MIN, Math.min(ALT_MAX, newAlt));
  return { alt: newAlt, az: newAz };
}

// --- Main render ---

function render() {
  const jd = julianDate();
  const lstDeg = lst(jd, LON_LA);
  const vf = buildViewFrame(view.alt, view.az, lstDeg);
  const scale = fovToScale(view.fov, Math.min(cx, cy));

  ctx.fillStyle = '#050510';
  ctx.fillRect(0, 0, W, H);

  renderMilkyWay(scale, vf);
  if (overlays.altAzGrid) renderAltAzGrid(scale, vf);
  if (overlays.eqGrid) renderEqGrid(scale, vf);
  if (overlays.ecliptic) renderEcliptic(scale, vf);
  renderDSOs(scale, vf);
  renderConstellationLines(scale, vf);
  renderStars(scale, vf);
  renderHorizon(scale, vf);
  renderCardinals(scale, vf);
  renderPlanets(scale, vf, jd);
  renderLabels(scale, vf);
  updateInfo(scale, vf);
  updateClock();
}

function frame() {
  render();
  requestAnimationFrame(frame);
}

// --- Input ---

function syncOverlayButtons() {
  const btnAz = document.getElementById('btn-altaz');
  const btnEq = document.getElementById('btn-eq');
  const btnEcl = document.getElementById('btn-ecl');
  if (btnAz) btnAz.classList.toggle('active', overlays.altAzGrid);
  if (btnEq) btnEq.classList.toggle('active', overlays.eqGrid);
  if (btnEcl) btnEcl.classList.toggle('active', overlays.ecliptic);
}

function setupInput() {
  canvas.style.cursor = 'grab';

  canvas.addEventListener('mousedown', (e) => {
    drag.active = true;
    drag.prevX = e.clientX;
    drag.prevY = e.clientY;
    canvas.style.cursor = 'grabbing';
  });

  window.addEventListener('mousemove', (e) => {
    cursorPx = e.clientX;
    cursorPy = e.clientY;
    if (!drag.active) return;
    const dx = e.clientX - drag.prevX, dy = e.clientY - drag.prevY;
    const degPerPx = view.fov / Math.min(W, H);
    const nv = applyDragRotation(view.alt, view.az, dx, dy, degPerPx);
    view.alt = nv.alt;
    view.az = nv.az;
    drag.prevX = e.clientX;
    drag.prevY = e.clientY;
  });

  window.addEventListener('mouseup', () => {
    drag.active = false;
    canvas.style.cursor = 'grab';
  });

  canvas.addEventListener('wheel', (e) => {
    e.preventDefault();
    let delta = e.deltaY;
    if (e.deltaMode === 1) delta *= 30;
    if (e.deltaMode === 2) delta *= 300;
    view.fov = Math.max(FOV_MIN, Math.min(FOV_MAX, view.fov * Math.pow(1.001, delta)));
  }, { passive: false });

  // Keyboard shortcuts
  window.addEventListener('keydown', (e) => {
    if (e.key === 'g' || e.key === 'G') { overlays.altAzGrid = !overlays.altAzGrid; syncOverlayButtons(); }
    if (e.key === 'q' || e.key === 'Q') { overlays.eqGrid = !overlays.eqGrid; syncOverlayButtons(); }
    if (e.key === 'e' || e.key === 'E') { overlays.ecliptic = !overlays.ecliptic; syncOverlayButtons(); }
  });

  // Overlay toggle buttons
  const btnAz = document.getElementById('btn-altaz');
  const btnEq = document.getElementById('btn-eq');
  const btnEcl = document.getElementById('btn-ecl');
  if (btnAz) btnAz.addEventListener('click', () => { overlays.altAzGrid = !overlays.altAzGrid; syncOverlayButtons(); });
  if (btnEq) btnEq.addEventListener('click', () => { overlays.eqGrid = !overlays.eqGrid; syncOverlayButtons(); });
  if (btnEcl) btnEcl.addEventListener('click', () => { overlays.ecliptic = !overlays.ecliptic; syncOverlayButtons(); });

  // Touch
  let lastTouchDist = null, lastTouchX = null, lastTouchY = null;

  canvas.addEventListener('touchstart', (e) => {
    e.preventDefault();
    if (e.touches.length === 1) {
      lastTouchX = e.touches[0].clientX;
      lastTouchY = e.touches[0].clientY;
      lastTouchDist = null;
    } else if (e.touches.length === 2) {
      lastTouchDist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY,
      );
    }
  }, { passive: false });

  canvas.addEventListener('touchmove', (e) => {
    e.preventDefault();
    if (e.touches.length === 1 && lastTouchX !== null) {
      const dx = e.touches[0].clientX - lastTouchX;
      const dy = e.touches[0].clientY - lastTouchY;
      const degPerPx = view.fov / Math.min(W, H);
      const nv = applyDragRotation(view.alt, view.az, dx, dy, degPerPx);
      view.alt = nv.alt;
      view.az = nv.az;
      lastTouchX = e.touches[0].clientX;
      lastTouchY = e.touches[0].clientY;
    } else if (e.touches.length === 2 && lastTouchDist !== null) {
      const dist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY,
      );
      view.fov = Math.max(FOV_MIN, Math.min(FOV_MAX, view.fov * lastTouchDist / dist));
      lastTouchDist = dist;
    }
  }, { passive: false });

  canvas.addEventListener('touchend', (e) => {
    if (e.touches.length < 2) lastTouchDist = null;
    if (e.touches.length < 1) { lastTouchX = null; lastTouchY = null; }
  }, { passive: false });

  window.addEventListener('resize', resize);
}

// --- Init ---

async function init() {
  resize();

  try {
    const resp = await fetch('data/stars.json');
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
    data = await resp.json();
  } catch (err) {
    const loadingEl = document.getElementById('loading');
    if (loadingEl) loadingEl.textContent = `failed to load star catalog: ${err.message}`;
    return;
  }

  // Sort stars by magnitude (brightest first) for zoom-based culling
  data.stars.sort((a, b) => a[2] - b[2]);

  // Pre-resolve constellation line endpoints
  for (const c of data.constellations) {
    c.resolvedLines = [];
    for (const pair of c.lines) {
      const s1 = data.hip[String(pair[0])];
      const s2 = data.hip[String(pair[1])];
      if (s1 && s2) c.resolvedLines.push([s1[0], s1[1], s2[0], s2[1]]);
    }
  }

  milkyWayPoints = buildMilkyWayPoints(data.milky_way);

  setupInput();

  const loadingEl = document.getElementById('loading');
  if (loadingEl) {
    loadingEl.classList.add('hidden');
    setTimeout(() => loadingEl.remove(), 800);
  }

  frame();
}

if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init);
} else {
  init();
}
